# Using pipreqs library to generate requirements.txt file
import subprocess

def generate_requirements_txt():
    # Run the command to generate the requirements.txt file with hashes
    subprocess.run("pip-compile --output-file=requirements.txt -h", shell=True)

# Using Poetry for dependency management
import os
from poetry.core.packages.package import Package

def update_poetry_lock_file():
    # Install or update the packages and then run this command to update the lock file
    subprocess.run("poetry update && poetry lock --no-interaction", shell=True)

def get_poetry_dependencies():
    # Get a list of dependencies with their versions from the lock file
    lock_data = {}
    lock_file_contents = open('pyproject.toml.lock').read()
    for line in lock_file_contents.split('\n'):
        if '=' in line:
            package_name, version = line.strip().split('=')
            lock_data[package_name] = version

def print_dependencies():
    # Print the list of dependencies
    get_poetry_dependencies()
    for dependency, version in lock_data.items():
        print(f"{dependency}=={version}")

if __name__ == "__main__":
    generate_requirements_txt()
    update_poetry_lock_file()